{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for stale sensor data timeout (> 1000ms since last valid reading) */
    bool is_stale = false;
    if (controller->has_valid_sensor && input.kind == CONTROLLER_INPUT_NONE) {
        uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
        if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            is_stale = true;
        }
    }

    /* Handle fault conditions: malformed input, sensor timeout, or stale data */
    if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        is_stale) {
        output.timed_out = true;
        controller_set_safe_off(controller);
        goto output_done;
    }

    /* Process temperature input */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        int temp = input.temperature_c;
        int prev_temp = controller->last_temperature_c;
        bool temp_rising = false;

        /* Check if temperature is rising compared to previous valid sample */
        if (controller->has_valid_sensor && temp > prev_temp) {
            temp_rising = true;
        }

        /* Update sensor state */
        controller->has_valid_sensor = true;
        controller->last_temperature_c = temp;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Apply control policy based on temperature bands */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* TEMP < 47: turn heater ON */
            controller_set_heating(controller);
