            /* 50 <= TEMP <= 52: check for rising temperature */
            if (temp_rising) {
                /* Rising: turn heater OFF early, treat as HOLDING */
                controller_set_holding(controller, false);
            } else {
                /* Not rising: hold previous safe actuator state (HOLDING) */
                controller_set_holding(controller, controller->heater_on);
            }
