        bool temp_rising = false;

        /* Check if temperature is rising compared to previous valid sample */
        if (controller->has_valid_sensor && temp > prev_temp) {
            temp_rising = true;
        }

        /* Update sensor state */
        controller->has_valid_sensor = true;
        controller->last_temperature_c = temp;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Apply control policy based on temperature bands */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* TEMP < 47: turn heater ON */
            controller_set_heating(controller);
        } else if (temp >= CONTROLLER_TEMP_HIGH_THRESHOLD + 1) {
            /* TEMP > 52: turn heater OFF (SAFE_OFF) */
            controller_set_safe_off(controller);
        } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* 47 <= TEMP < 50: hold previous safe actuator state (HOLDING) */
            controller_set_holding(controller, controller->heater_on);
        } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* 50 <= TEMP <= 52: check for rising temperature */
            if (temp_rising) {
                /* Rising: turn heater OFF early, treat as HOLDING */
                controller_set_holding(controller, false);
            } else {
                /* Not rising: hold previous safe actuator state (HOLDING) */
                controller_set_holding(controller, controller->heater_on);
            }
        } else {
            /* Default to safe off for any other case */
            controller_set_safe_off(controller);
        }
    } else if (input.kind == CONTROLLER_INPUT_NONE && !is_stale) {
        /* No new input but not stale: maintain current state */
        /* Do nothing, keep existing heater state and state */
    }

output_done:
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}
